text:
  1	/* ============================================================
  2	   Nikhil Komakula — Portfolio
  3	   Dark, modern, AI-inspired design system
  4	   ============================================================ */
  5	
  6	/* ------------------------------------------------------------
  7	   Design tokens
  8	   NOTE: A "digital twin" chat widget is planned for a future
  9	   iteration. Conventions reserved for it:
 10	   - Fixed bottom-right viewport corner stays free of UI.
 11	   - z-index scale: nav 100, scroll-progress 200 → twin widget 150.
 12	   - The widget should consume these tokens (--gradient, --surface,
 13	     --border, --radius, fonts) so it feels native to the site.
 14	   ------------------------------------------------------------ */
 15	:root {
 16	  --bg: #070b14;
 17	  --bg-alt: #0b1020;
 18	  --surface: rgba(255, 255, 255, 0.04);
 19	  --surface-strong: rgba(255, 255, 255, 0.07);
 20	  --border: rgba(255, 255, 255, 0.09);
 21	  --text: #e6ebf5;
 22	  --text-dim: #97a3ba;
 23	  --accent-1: #22d3ee; /* cyan */
 24	  --accent-2: #818cf8; /* indigo */
 25	  --accent-3: #e879f9; /* fuchsia */
 26	  --gradient: linear-gradient(100deg, var(--accent-1), var(--accent-2) 55%, var(--accent-3));
 27	  --font-display: "Space Grotesk", system-ui, sans-serif;
 28	  --font-body: "Inter", system-ui, sans-serif;
 29	  --font-mono: "JetBrains Mono", monospace;
 30	  --radius: 18px;
 31	  --shadow: 0 20px 60px rgba(0, 0, 0, 0.45);
 32	  --nav-h: 72px;
 33	}
 34	
 35	* { margin: 0; padding: 0; box-sizing: border-box; }
 36	
 37	html { scroll-behavior: smooth; scroll-padding-top: calc(var(--nav-h) + 12px); }
 38	
 39	body {
 40	  background: var(--bg);
 41	  color: var(--text);
 42	  font-family: var(--font-body);
 43	  font-size: 16.5px;
 44	  line-height: 1.65;
 45	  -webkit-font-smoothing: antialiased;
 46	  overflow-x: hidden;
 47	}
 48	
 49	::selection { background: rgba(129, 140, 248, 0.45); color: #fff; }
 50	
 51	.container { max-width: 1120px; margin: 0 auto; padding: 0 24px; }
 52	.accent { color: var(--accent-1); }
 53	
 54	.gradient-text {
 55	  background: var(--gradient);
 56	  -webkit-background-clip: text;
 57	  background-clip: text;
 58	  color: transparent;
 59	}
 60	
 61	/* ---------- Scroll progress ---------- */
 62	.scroll-progress {
 63	  position: fixed; inset: 0 0 auto 0; height: 3px; z-index: 200;
 64	  background: transparent;
 65	}
 66	.scroll-progress span {
 67	  display: block; height: 100%; width: 0;
 68	  background: var(--gradient);
 69	  transition: width 0.08s linear;
 70	}
 71	
 72	/* ---------- Nav ---------- */
 73	.nav {
 74	  position: fixed; inset: 0 0 auto 0; z-index: 100;
 75	  height: var(--nav-h);
 76	  backdrop-filter: blur(14px);
 77	  -webkit-backdrop-filter: blur(14px);
 78	  background: rgba(7, 11, 20, 0.55);
 79	  border-bottom: 1px solid transparent;
 80	  transition: border-color 0.3s ease, background 0.3s ease;
 81	}
 82	.nav--scrolled { border-bottom-color: var(--border); background: rgba(7, 11, 20, 0.82); }
 83	
 84	.nav__inner {
 85	  max-width: 1120px; margin: 0 auto; padding: 0 24px;
 86	  height: 100%; display: flex; align-items: center; justify-content: space-between;
 87	}
 88	.nav__logo { display: flex; align-items: center; gap: 10px; text-decoration: none; color: var(--text); }
 89	.nav__logo-mark {
 90	  display: grid; place-items: center; width: 38px; height: 38px;
 91	  font-family: var(--font-display); font-weight: 700; font-size: 0.95rem;
 92	  background: var(--gradient); color: #060913; border-radius: 11px;
 93	}
 94	.nav__logo-text { font-family: var(--font-display); font-weight: 600; letter-spacing: 0.2px; }
 95	
 96	.nav__links { display: flex; align-items: center; gap: 28px; }
 97	.nav__links a {
 98	  color: var(--text-dim); text-decoration: none; font-size: 0.92rem; font-weight: 500;
 99	  transition: color 0.2s ease;
100	}
101	.nav__links a:hover { color: var(--text); }
102	.nav__cta {
103	  padding: 9px 18px; border: 1px solid var(--border); border-radius: 999px;
104	  color: var(--text) !important;
105	  background: var(--surface);
106	  transition: border-color 0.25s ease, background 0.25s ease;
107	}
108	.nav__cta:hover { border-color: var(--accent-1); background: rgba(34, 211, 238, 0.08); }
109	
110	.nav__burger {
111	  display: none; flex-direction: column; gap: 5px;
112	  background: none; border: 0; cursor: pointer; padding: 8px;
113	}
114	.nav__burger span { width: 24px; height: 2px; background: var(--text); transition: all 0.3s ease; }
115	
116	/* ---------- Buttons ---------- */
117	.btn {
118	  display: inline-flex; align-items: center; justify-content: center; gap: 8px;
119	  padding: 13px 28px; border-radius: 999px;
120	  font-family: var(--font-display); font-weight: 600; font-size: 0.95rem;
121	  text-decoration: none; cursor: pointer; border: 1px solid transparent;
122	  transition: transform 0.2s ease, box-shadow 0.25s ease, border-color 0.25s ease, background 0.25s ease;
123	}
124	.btn--primary {
125	  background: var(--gradient); color: #060913;
126	  box-shadow: 0 8px 30px rgba(99, 102, 241, 0.35);
127	}
128	.btn--primary:hover { transform: translateY(-2px); box-shadow: 0 14px 40px rgba(99, 102, 241, 0.5); }
129	.btn--ghost {
130	  border-color: var(--border); color: var(--text); background: var(--surface);
131	}
132	.btn--ghost:hover { border-color: var(--accent-2); transform: translateY(-2px); }
133	.btn--lg { padding: 16px 34px; font-size: 1.05rem; }
134	
135	/* ---------- Hero ---------- */
136	.hero {
137	  position: relative; min-height: 100svh;
138	  display: flex; align-items: center; justify-content: center;
139	  overflow: hidden; text-align: center;
140	  padding: calc(var(--nav-h) + 40px) 24px 80px;
141	}
142	#neuralCanvas { position: absolute; inset: 0; width: 100%; height: 100%; opacity: 0.55; }
143	.hero__glow {
144	  position: absolute; width: 900px; height: 900px; border-radius: 50%;
145	  background: radial-gradient(circle, rgba(129, 140, 248, 0.16) 0%, rgba(34, 211, 238, 0.07) 40%, transparent 70%);
146	  top: 50%; left: 50%; transform: translate(-50%, -50%);
147	  pointer-events: none;
148	}
149	
150	.hero__content { position: relative; z-index: 2; max-width: 860px; }
151	
152	.hero__eyebrow {
153	  display: inline-flex; align-items: center; gap: 10px;
154	  font-family: var(--font-mono); font-size: 0.85rem; letter-spacing: 0.06em;
155	  color: var(--accent-1);
156	  border: 1px solid rgba(34, 211, 238, 0.3); border-radius: 999px;
157	  padding: 8px 18px; margin-bottom: 28px;
158	  background: rgba(34, 211, 238, 0.06);
159	}
160	.pulse-dot {
161	  width: 8px; height: 8px; border-radius: 50%;
162	  background: #34d399;
163	  box-shadow: 0 0 0 0 rgba(52, 211, 153, 0.7);
164	  animation: pulse 2s infinite;
165	}
166	@keyframes pulse {
167	  0% { box-shadow: 0 0 0 0 rgba(52, 211, 153, 0.6); }
168	  70% { box-shadow: 0 0 0 9px rgba(52, 211, 153, 0); }
169	  100% { box-shadow: 0 0 0 0 rgba(52, 211, 153, 0); }
170	}
171	
172	.hero__title {
173	  font-family: var(--font-display);
174	  font-size: clamp(3rem, 8.5vw, 5.6rem);
175	  font-weight: 700; line-height: 1.05; letter-spacing: -0.02em;
176	  margin-bottom: 22px;
177	}
178	
179	.hero__role {
180	  font-family: var(--font-display);
181	  font-size: clamp(1.15rem, 2.6vw, 1.6rem);
182	  color: var(--text-dim); font-weight: 500; margin-bottom: 22px;
183	  min-height: 2.2em;
184	}
185	.typed-wrap { color: var(--text); white-space: nowrap; }
186	#typed {
187	  background: var(--gradient);
188	  -webkit-background-clip: text; background-clip: text; color: transparent;
189	  font-weight: 700;
190	}
191	.typed-caret { color: var(--accent-1); animation: blink 1s step-end infinite; font-weight: 400; }
192	@keyframes blink { 50% { opacity: 0; } }
193	
194	.hero__tagline {
195	  max-width: 640px; margin: 0 auto 40px; color: var(--text-dim); font-size: 1.06rem;
196	}
197	.hero__tagline strong { color: var(--text); }
198	
199	.hero__actions { display: flex; gap: 16px; justify-content: center; flex-wrap: wrap; margin-bottom: 40px; }
200	
201	.hero__socials { display: flex; gap: 14px; justify-content: center; }
202	.hero__socials a {
203	  display: grid; place-items: center; width: 46px; height: 46px;
204	  color: var(--text-dim); border: 1px solid var(--border); border-radius: 14px;
205	  background: var(--surface);
206	  transition: all 0.25s ease;
207	}
208	.hero__socials a:hover { color: var(--accent-1); border-color: var(--accent-1); transform: translateY(-3px); }
209	
210	.hero__scroll {
211	  position: absolute; bottom: 28px; left: 50%; transform: translateX(-50%); z-index: 2;
212	}
213	.hero__scroll-mouse {
214	  display: block; width: 26px; height: 42px;
215	  border: 2px solid var(--text-dim); border-radius: 14px; position: relative;
216	}
217	.hero__scroll-mouse span {
218	  position: absolute; top: 7px; left: 50%; transform: translateX(-50%);
219	  width: 4px; height: 8px; border-radius: 4px; background: var(--accent-1);
220	  animation: scrollWheel 1.8s ease-in-out infinite;
221	}
222	@keyframes scrollWheel {
223	  0% { opacity: 1; transform: translate(-50%, 0); }
224	  70% { opacity: 0; transform: translate(-50%, 12px); }
225	  100% { opacity: 0; transform: translate(-50%, 0); }
226	}
227	
228	/* ---------- Stats ---------- */
229	.stats { padding: 30px 0 10px; }
230	.stats__grid {
231	  display: grid; grid-template-columns: repeat(4, 1fr); gap: 20px;
232	  border: 1px solid var(--border); border-radius: var(--radius);
233	  background: linear-gradient(180deg, rgba(255,255,255,0.045), rgba(255,255,255,0.015));
234	  padding: 38px 30px;
235	}
236	.stat { text-align: center; }
237	.stat__num {
238	  display: block; font-family: var(--font-display); font-weight: 700;
239	  font-size: clamp(2.2rem, 4.5vw, 3.2rem);
240	  background: var(--gradient);
241	  -webkit-background-clip: text; background-clip: text; color: transparent;
242	}
243	.stat__label { color: var(--text-dim); font-size: 0.92rem; }
244	
245	/* ---------- Sections ---------- */
246	.section { padding: 110px 0; position: relative; }
247	.section--alt {
248	  background:
249	    radial-gradient(1200px 500px at 80% 0%, rgba(129, 140, 248, 0.06), transparent 60%),
250	    var(--bg-alt);
251	}
252	.section__kicker {
253	  font-family: var(--font-mono); font-size: 0.82rem; letter-spacing: 0.18em;
254	  text-transform: uppercase; color: var(--accent-1); margin-bottom: 14px;
255	}
256	.section__title {
257	  font-family: var(--font-display);
258	  font-size: clamp(2rem, 4.6vw, 3rem);
259	  font-weight: 700; letter-spacing: -0.015em; line-height: 1.15;
260	  margin-bottom: 56px;
261	}
262	
263	/* ---------- About ---------- */
264	.about__grid { display: grid; grid-template-columns: 1.3fr 1fr; gap: 48px; align-items: start; }
265	.about__text p { margin-bottom: 20px; color: var(--text-dim); font-size: 1.04rem; }
266	.about__text strong { color: var(--text); }
267	.about__text em { color: var(--accent-1); font-style: normal; }
268	
269	.about__cards { display: grid; gap: 18px; }
270	.glass-card {
271	  border: 1px solid var(--border); border-radius: var(--radius);
272	  background: var(--surface); padding: 24px 26px;
273	  transition: transform 0.25s ease, border-color 0.25s ease;
274	}
275	.glass-card:hover { transform: translateY(-4px); border-color: rgba(129, 140, 248, 0.5); }
276	.glass-card__icon { font-size: 1.6rem; margin-bottom: 10px; }
277	.glass-card h3 { font-family: var(--font-display); font-size: 1.05rem; margin-bottom: 6px; }
278	.glass-card p { color: var(--text-dim); font-size: 0.93rem; }
279	
280	/* ---------- Timeline ---------- */
281	.timeline { position: relative; padding-left: 36px; }
282	.timeline::before {
283	  content: ""; position: absolute; left: 8px; top: 6px; bottom: 6px; width: 2px;
284	  background: linear-gradient(180deg, var(--accent-1), var(--accent-2), transparent);
285	  opacity: 0.5;
286	}
287	.timeline__item { position: relative; margin-bottom: 34px; }
288	.timeline__marker {
289	  position: absolute; left: -36px; top: 8px;
290	  width: 18px; height: 18px; border-radius: 50%;
291	  background: var(--bg); border: 3px solid var(--accent-2);
292	}
293	.timeline__item[data-current="true"] .timeline__marker {
294	  border-color: var(--accent-1);
295	  box-shadow: 0 0 0 5px rgba(34, 211, 238, 0.15), 0 0 18px rgba(34, 211, 238, 0.5);
296	}
297	
298	.timeline__card {
299	  border: 1px solid var(--border); border-radius: var(--radius);
300	  background: var(--surface); padding: 28px 30px;
301	  transition: transform 0.25s ease, border-color 0.25s ease, background 0.25s ease;
302	}
303	.timeline__card:hover { transform: translateX(6px); border-color: rgba(34, 211, 238, 0.4); background: var(--surface-strong); }
304	
305	.timeline__head { display: flex; justify-content: space-between; gap: 18px; flex-wrap: wrap; margin-bottom: 14px; }
306	.timeline__head h3 { font-family: var(--font-display); font-size: 1.18rem; line-height: 1.35; }
307	.timeline__sep { color: var(--accent-2); }
308	.timeline__company { color: var(--accent-1); font-weight: 600; font-size: 0.95rem; margin-top: 2px; }
309	.timeline__meta {
310	  display: flex; align-items: center; gap: 10px; flex-wrap: wrap;
311	  color: var(--text-dim); font-size: 0.86rem; font-family: var(--font-mono);
312	}
313	.badge--live {
314	  padding: 3px 12px; border-radius: 999px; font-size: 0.72rem; font-weight: 600;
315	  background: rgba(52, 211, 153, 0.14); color: #34d399; border: 1px solid rgba(52, 211, 153, 0.35);
316	}
317	
318	.timeline__card ul { list-style: none; display: grid; gap: 9px; margin-bottom: 16px; }
319	.timeline__card ul li {
320	  position: relative; padding-left: 22px; color: var(--text-dim); font-size: 0.95rem;
321	}
322	.timeline__card ul li::before {
323	  content: "▸"; position: absolute; left: 0; color: var(--accent-1);
324	}
325	.timeline__card--compact ul { margin-bottom: 0; }
326	
327	.timeline__tags { display: flex; flex-wrap: wrap; gap: 8px; }
328	.timeline__tags span {
329	  font-family: var(--font-mono); font-size: 0.74rem;
330	  padding: 5px 12px; border-radius: 999px;
331	  color: var(--accent-2); background: rgba(129, 140, 248, 0.1);
332	  border: 1px solid rgba(129, 140, 248, 0.25);
333	}
334	
335	/* ---------- Projects ---------- */
336	.projects__grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 22px; }
337	.project {
338	  position: relative;
339	  border: 1px solid var(--border); border-radius: var(--radius);
340	  background: var(--surface); padding: 28px;
341	  display: flex; flex-direction: column;
342	  transition: transform 0.28s ease, border-color 0.28s ease, box-shadow 0.28s ease;
343	}
344	.project:hover {
345	  transform: translateY(-6px);
346	  border-color: rgba(34, 211, 238, 0.45);
347	  box-shadow: 0 18px 50px rgba(0, 0, 0, 0.4);
348	}
349	.project__link-overlay { position: absolute; inset: 0; z-index: 1; border-radius: var(--radius); }
350	.project__top { display: flex; justify-content: space-between; align-items: center; margin-bottom: 16px; }
351	.project__icon { font-size: 1.7rem; }
352	.project__domain {
353	  display: inline-flex; align-items: center; gap: 6px;
354	  font-family: var(--font-mono); font-size: 0.72rem; letter-spacing: 0.08em;
355	  color: var(--accent-1); text-transform: uppercase;
356	}
357	.project h3 { font-family: var(--font-display); font-size: 1.22rem; margin-bottom: 10px; }
358	.project__gh { font-size: 0.72rem; color: var(--accent-1); font-family: var(--font-mono); vertical-align: middle; }
359	.project p { color: var(--text-dim); font-size: 0.93rem; margin-bottom: 16px; }
360	.project__wins { list-style: none; display: grid; gap: 7px; margin-bottom: 18px; }
361	.project__wins li {
362	  position: relative; padding-left: 20px; font-size: 0.87rem; color: var(--text);
363	}
364	.project__wins li::before { content: "✦"; position: absolute; left: 0; color: var(--accent-3); font-size: 0.75rem; top: 2px; }
365	.project__tags { display: flex; flex-wrap: wrap; gap: 7px; margin-top: auto; }
366	.project__tags span {
367	  font-family: var(--font-mono); font-size: 0.72rem;
368	  padding: 4px 11px; border-radius: 999px;
369	  color: var(--text-dim); background: rgba(255, 255, 255, 0.05);
370	  border: 1px solid var(--border);
371	}
372	.project--cta {
373	  align-items: flex-start; justify-content: center; gap: 6px;
374	  background: linear-gradient(145deg, rgba(34, 211, 238, 0.07), rgba(232, 121, 249, 0.06));
375	  border-style: dashed;
376	}
377	
378	/* ---------- Skills ---------- */
379	.skills__grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 22px; }
380	.skill-group {
381	  border: 1px solid var(--border); border-radius: var(--radius);
382	  background: var(--surface); padding: 26px 28px;
383	  transition: border-color 0.25s ease;
384	}
385	.skill-group:hover { border-color: rgba(129, 140, 248, 0.45); }
386	.skill-group h3 {
387	  font-family: var(--font-display); font-size: 1.06rem; margin-bottom: 16px;
388	  display: flex; align-items: center; gap: 10px;
389	}
390	.chips { display: flex; flex-wrap: wrap; gap: 9px; }
391	.chips span {
392	  font-size: 0.83rem; padding: 7px 14px; border-radius: 999px;
393	  color: var(--text-dim); background: rgba(255, 255, 255, 0.045);
394	  border: 1px solid var(--border);
395	  transition: all 0.2s ease; cursor: default;
396	}
397	.chips span:hover {
398	  color: var(--text); border-color: var(--accent-1);
399	  background: rgba(34, 211, 238, 0.08); transform: translateY(-2px);
400	}
401	
402	/* ---------- Credentials ---------- */
403	.cred__grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 22px; }
404	.cred__col {
405	  border: 1px solid var(--border); border-radius: var(--radius);
406	  background: var(--surface); padding: 28px;
407	}
408	.cred__heading { font-family: var(--font-display); font-size: 1.1rem; margin-bottom: 18px; }
409	.cred__list { list-style: none; display: grid; gap: 12px; }
410	.cred__list li {
411	  position: relative; padding-left: 20px; color: var(--text-dim); font-size: 0.92rem;
412	}
413	.cred__list li::before { content: "◆"; position: absolute; left: 0; top: 3px; color: var(--accent-2); font-size: 0.6rem; }
414	.cred__list strong { color: var(--text); }
415	.cred__list--edu li { display: grid; gap: 2px; }
416	.cred__list--edu span { font-size: 0.85rem; }
417	
418	/* ---------- Contact ---------- */
419	.section--contact {
420	  background:
421	    radial-gradient(800px 400px at 50% 100%, rgba(129, 140, 248, 0.12), transparent 65%),
422	    var(--bg-alt);
423	  text-align: center;
424	}
425	.contact__inner { max-width: 760px; }
426	.contact__blurb { color: var(--text-dim); font-size: 1.08rem; max-width: 560px; margin: 0 auto 36px; }
427	.contact__actions { margin-bottom: 34px; }
428	.contact__links {
429	  display: flex; justify-content: center; gap: 26px; flex-wrap: wrap;
430	  color: var(--text-dim); font-size: 0.95rem;
431	}
432	.contact__links a { color: var(--text-dim); text-decoration: none; transition: color 0.2s ease; }
433	.contact__links a:hover { color: var(--accent-1); }
434	
435	/* ---------- Footer ---------- */
436	.footer { border-top: 1px solid var(--border); padding: 28px 0; }
437	.footer__inner { display: flex; justify-content: space-between; align-items: center; gap: 16px; flex-wrap: wrap; }
438	.footer p { color: var(--text-dim); font-size: 0.88rem; }
439	.footer__top {
440	  display: grid; place-items: center; width: 42px; height: 42px;
441	  color: var(--text); text-decoration: none;
442	  border: 1px solid var(--border); border-radius: 12px; background: var(--surface);
443	  transition: all 0.25s ease;
444	}
445	.footer__top:hover { border-color: var(--accent-1); transform: translateY(-3px); }
446	
447	/* ---------- Reveal animation ---------- */
448	.reveal {
449	  opacity: 0; transform: translateY(28px);
450	  transition: opacity 0.7s cubic-bezier(0.22, 1, 0.36, 1), transform 0.7s cubic-bezier(0.22, 1, 0.36, 1);
451	}
452	.reveal.is-visible { opacity: 1; transform: none; }
453	
454	@media (prefers-reduced-motion: reduce) {
455	  html { scroll-behavior: auto; }
456	  .reveal { opacity: 1; transform: none; transition: none; }
457	  .pulse-dot, .typed-caret, .hero__scroll-mouse span { animation: none; }
458	}
459	
460	/* ---------- Responsive ---------- */
461	@media (max-width: 960px) {
462	  .about__grid { grid-template-columns: 1fr; }
463	  .projects__grid { grid-template-columns: repeat(2, 1fr); }
464	  .cred__grid { grid-template-columns: 1fr; }
465	  .stats__grid { grid-template-columns: repeat(2, 1fr); gap: 30px; }
466	}
467	
468	@media (max-width: 720px) {
469	  .section { padding: 80px 0; }
470	  .projects__grid { grid-template-columns: 1fr; }
471	  .skills__grid { grid-template-columns: 1fr; }
472	  .timeline { padding-left: 30px; }
473	  .timeline__marker { left: -30px; }
474	  .timeline__card:hover { transform: none; }
475	
476	  .nav__links {
477	    position: fixed; inset: var(--nav-h) 0 auto 0;
478	    flex-direction: column; align-items: stretch; gap: 0;
479	    background: rgba(7, 11, 20, 0.97);
480	    border-bottom: 1px solid var(--border);
481	    padding: 12px 24px 22px;
482	    transform: translateY(-130%);
483	    transition: transform 0.35s cubic-bezier(0.22, 1, 0.36, 1);
484	  }
485	  .nav__links.is-open { transform: translateY(0); }
486	  .nav__links a { padding: 13px 4px; font-size: 1.02rem; }
487	  .nav__cta { text-align: center; margin-top: 10px; }
488	  .nav__burger { display: flex; }
489	  .nav__burger.is-open span:nth-child(1) { transform: translateY(7px) rotate(45deg); }
490	  .nav__burger.is-open span:nth-child(2) { opacity: 0; }
491	  .nav__burger.is-open span:nth-child(3) { transform: translateY(-7px) rotate(-45deg); }
492	}

content.text:
  1	/* ============================================================
  2	   Nikhil Komakula — Portfolio
  3	   Dark, modern, AI-inspired design system
  4	   ============================================================ */
  5	
  6	/* ------------------------------------------------------------
  7	   Design tokens
  8	   NOTE: A "digital twin" chat widget is planned for a future
  9	   iteration. Conventions reserved for it:
 10	   - Fixed bottom-right viewport corner stays free of UI.
 11	   - z-index scale: nav 100, scroll-progress 200 → twin widget 150.
 12	   - The widget should consume these tokens (--gradient, --surface,
 13	     --border, --radius, fonts) so it feels native to the site.
 14	   ------------------------------------------------------------ */
 15	:root {
 16	  --bg: #070b14;
 17	  --bg-alt: #0b1020;
 18	  --surface: rgba(255, 255, 255, 0.04);
 19	  --surface-strong: rgba(255, 255, 255, 0.07);
 20	  --border: rgba(255, 255, 255, 0.09);
 21	  --text: #e6ebf5;
 22	  --text-dim: #97a3ba;
 23	  --accent-1: #22d3ee; /* cyan */
 24	  --accent-2: #818cf8; /* indigo */
 25	  --accent-3: #e879f9; /* fuchsia */
 26	  --gradient: linear-gradient(100deg, var(--accent-1), var(--accent-2) 55%, var(--accent-3));
 27	  --font-display: "Space Grotesk", system-ui, sans-serif;
 28	  --font-body: "Inter", system-ui, sans-serif;
 29	  --font-mono: "JetBrains Mono", monospace;
 30	  --radius: 18px;
 31	  --shadow: 0 20px 60px rgba(0, 0, 0, 0.45);
 32	  --nav-h: 72px;
 33	}
 34	
 35	* { margin: 0; padding: 0; box-sizing: border-box; }
 36	
 37	html { scroll-behavior: smooth; scroll-padding-top: calc(var(--nav-h) + 12px); }
 38	
 39	body {
 40	  background: var(--bg);
 41	  color: var(--text);
 42	  font-family: var(--font-body);
 43	  font-size: 16.5px;
 44	  line-height: 1.65;
 45	  -webkit-font-smoothing: antialiased;
 46	  overflow-x: hidden;
 47	}
 48	
 49	::selection { background: rgba(129, 140, 248, 0.45); color: #fff; }
 50	
 51	.container { max-width: 1120px; margin: 0 auto; padding: 0 24px; }
 52	.accent { color: var(--accent-1); }
 53	
 54	.gradient-text {
 55	  background: var(--gradient);
 56	  -webkit-background-clip: text;
 57	  background-clip: text;
 58	  color: transparent;
 59	}
 60	
 61	/* ---------- Scroll progress ---------- */
 62	.scroll-progress {
 63	  position: fixed; inset: 0 0 auto 0; height: 3px; z-index: 200;
 64	  background: transparent;
 65	}
 66	.scroll-progress span {
 67	  display: block; height: 100%; width: 0;
 68	  background: var(--gradient);
 69	  transition: width 0.08s linear;
 70	}
 71	
 72	/* ---------- Nav ---------- */
 73	.nav {
 74	  position: fixed; inset: 0 0 auto 0; z-index: 100;
 75	  height: var(--nav-h);
 76	  backdrop-filter: blur(14px);
 77	  -webkit-backdrop-filter: blur(14px);
 78	  background: rgba(7, 11, 20, 0.55);
 79	  border-bottom: 1px solid transparent;
 80	  transition: border-color 0.3s ease, background 0.3s ease;
 81	}
 82	.nav--scrolled { border-bottom-color: var(--border); background: rgba(7, 11, 20, 0.82); }
 83	
 84	.nav__inner {
 85	  max-width: 1120px; margin: 0 auto; padding: 0 24px;
 86	  height: 100%; display: flex; align-items: center; justify-content: space-between;
 87	}
 88	.nav__logo { display: flex; align-items: center; gap: 10px; text-decoration: none; color: var(--text); }
 89	.nav__logo-mark {
 90	  display: grid; place-items: center; width: 38px; height: 38px;
 91	  font-family: var(--font-display); font-weight: 700; font-size: 0.95rem;
 92	  background: var(--gradient); color: #060913; border-radius: 11px;
 93	}
 94	.nav__logo-text { font-family: var(--font-display); font-weight: 600; letter-spacing: 0.2px; }
 95	
 96	.nav__links { display: flex; align-items: center; gap: 28px; }
 97	.nav__links a {
 98	  color: var(--text-dim); text-decoration: none; font-size: 0.92rem; font-weight: 500;
 99	  transition: color 0.2s ease;
100	}
101	.nav__links a:hover { color: var(--text); }
102	.nav__cta {
103	  padding: 9px 18px; border: 1px solid var(--border); border-radius: 999px;
104	  color: var(--text) !important;
105	  background: var(--surface);
106	  transition: border-color 0.25s ease, background 0.25s ease;
107	}
108	.nav__cta:hover { border-color: var(--accent-1); background: rgba(34, 211, 238, 0.08); }
109	
110	.nav__burger {
111	  display: none; flex-direction: column; gap: 5px;
112	  background: none; border: 0; cursor: pointer; padding: 8px;
113	}
114	.nav__burger span { width: 24px; height: 2px; background: var(--text); transition: all 0.3s ease; }
115	
116	/* ---------- Buttons ---------- */
117	.btn {
118	  display: inline-flex; align-items: center; justify-content: center; gap: 8px;
119	  padding: 13px 28px; border-radius: 999px;
120	  font-family: var(--font-display); font-weight: 600; font-size: 0.95rem;
121	  text-decoration: none; cursor: pointer; border: 1px solid transparent;
122	  transition: transform 0.2s ease, box-shadow 0.25s ease, border-color 0.25s ease, background 0.25s ease;
123	}
124	.btn--primary {
125	  background: var(--gradient); color: #060913;
126	  box-shadow: 0 8px 30px rgba(99, 102, 241, 0.35);
127	}
128	.btn--primary:hover { transform: translateY(-2px); box-shadow: 0 14px 40px rgba(99, 102, 241, 0.5); }
129	.btn--ghost {
130	  border-color: var(--border); color: var(--text); background: var(--surface);
131	}
132	.btn--ghost:hover { border-color: var(--accent-2); transform: translateY(-2px); }
133	.btn--lg { padding: 16px 34px; font-size: 1.05rem; }
134	
135	/* ---------- Hero ---------- */
136	.hero {
137	  position: relative; min-height: 100svh;
138	  display: flex; align-items: center; justify-content: center;
139	  overflow: hidden; text-align: center;
140	  padding: calc(var(--nav-h) + 40px) 24px 80px;
141	}
142	#neuralCanvas { position: absolute; inset: 0; width: 100%; height: 100%; opacity: 0.55; }
143	.hero__glow {
144	  position: absolute; width: 900px; height: 900px; border-radius: 50%;
145	  background: radial-gradient(circle, rgba(129, 140, 248, 0.16) 0%, rgba(34, 211, 238, 0.07) 40%, transparent 70%);
146	  top: 50%; left: 50%; transform: translate(-50%, -50%);
147	  pointer-events: none;
148	}
149	
150	.hero__content { position: relative; z-index: 2; max-width: 860px; }
151	
152	.hero__eyebrow {
153	  display: inline-flex; align-items: center; gap: 10px;
154	  font-family: var(--font-mono); font-size: 0.85rem; letter-spacing: 0.06em;
155	  color: var(--accent-1);
156	  border: 1px solid rgba(34, 211, 238, 0.3); border-radius: 999px;
157	  padding: 8px 18px; margin-bottom: 28px;
158	  background: rgba(34, 211, 238, 0.06);
159	}
160	.pulse-dot {
161	  width: 8px; height: 8px; border-radius: 50%;
162	  background: #34d399;
163	  box-shadow: 0 0 0 0 rgba(52, 211, 153, 0.7);
164	  animation: pulse 2s infinite;
165	}
166	@keyframes pulse {
167	  0% { box-shadow: 0 0 0 0 rgba(52, 211, 153, 0.6); }
168	  70% { box-shadow: 0 0 0 9px rgba(52, 211, 153, 0); }
169	  100% { box-shadow: 0 0 0 0 rgba(52, 211, 153, 0); }
170	}
171	
172	.hero__title {
173	  font-family: var(--font-display);
174	  font-size: clamp(3rem, 8.5vw, 5.6rem);
175	  font-weight: 700; line-height: 1.05; letter-spacing: -0.02em;
176	  margin-bottom: 22px;
177	}
178	
179	.hero__role {
180	  font-family: var(--font-display);
181	  font-size: clamp(1.15rem, 2.6vw, 1.6rem);
182	  color: var(--text-dim); font-weight: 500; margin-bottom: 22px;
183	  min-height: 2.2em;
184	}
185	.typed-wrap { color: var(--text); white-space: nowrap; }
186	#typed {
187	  background: var(--gradient);
188	  -webkit-background-clip: text; background-clip: text; color: transparent;
189	  font-weight: 700;
190	}
191	.typed-caret { color: var(--accent-1); animation: blink 1s step-end infinite; font-weight: 400; }
192	@keyframes blink { 50% { opacity: 0; } }
193	
194	.hero__tagline {
195	  max-width: 640px; margin: 0 auto 40px; color: var(--text-dim); font-size: 1.06rem;
196	}
197	.hero__tagline strong { color: var(--text); }
198	
199	.hero__actions { display: flex; gap: 16px; justify-content: center; flex-wrap: wrap; margin-bottom: 40px; }
200	
201	.hero__socials { display: flex; gap: 14px; justify-content: center; }
202	.hero__socials a {
203	  display: grid; place-items: center; width: 46px; height: 46px;
204	  color: var(--text-dim); border: 1px solid var(--border); border-radius: 14px;
205	  background: var(--surface);
206	  transition: all 0.25s ease;
207	}
208	.hero__socials a:hover { color: var(--accent-1); border-color: var(--accent-1); transform: translateY(-3px); }
209	
210	.hero__scroll {
211	  position: absolute; bottom: 28px; left: 50%; transform: translateX(-50%); z-index: 2;
212	}
213	.hero__scroll-mouse {
214	  display: block; width: 26px; height: 42px;
215	  border: 2px solid var(--text-dim); border-radius: 14px; position: relative;
216	}
217	.hero__scroll-mouse span {
218	  position: absolute; top: 7px; left: 50%; transform: translateX(-50%);
219	  width: 4px; height: 8px; border-radius: 4px; background: var(--accent-1);
220	  animation: scrollWheel 1.8s ease-in-out infinite;
221	}
222	@keyframes scrollWheel {
223	  0% { opacity: 1; transform: translate(-50%, 0); }
224	  70% { opacity: 0; transform: translate(-50%, 12px); }
225	  100% { opacity: 0; transform: translate(-50%, 0); }
226	}
227	
228	/* ---------- Stats ---------- */
229	.stats { padding: 30px 0 10px; }
230	.stats__grid {
231	  display: grid; grid-template-columns: repeat(4, 1fr); gap: 20px;
232	  border: 1px solid var(--border); border-radius: var(--radius);
233	  background: linear-gradient(180deg, rgba(255,255,255,0.045), rgba(255,255,255,0.015));
234	  padding: 38px 30px;
235	}
236	.stat { text-align: center; }
237	.stat__num {
238	  display: block; font-family: var(--font-display); font-weight: 700;
239	  font-size: clamp(2.2rem, 4.5vw, 3.2rem);
240	  background: var(--gradient);
241	  -webkit-background-clip: text; background-clip: text; color: transparent;
242	}
243	.stat__label { color: var(--text-dim); font-size: 0.92rem; }
244	
245	/* ---------- Sections ---------- */
246	.section { padding: 110px 0; position: relative; }
247	.section--alt {
248	  background:
249	    radial-gradient(1200px 500px at 80% 0%, rgba(129, 140, 248, 0.06), transparent 60%),
250	    var(--bg-alt);
251	}
252	.section__kicker {
253	  font-family: var(--font-mono); font-size: 0.82rem; letter-spacing: 0.18em;
254	  text-transform: uppercase; color: var(--accent-1); margin-bottom: 14px;
255	}
256	.section__title {
257	  font-family: var(--font-display);
258	  font-size: clamp(2rem, 4.6vw, 3rem);
259	  font-weight: 700; letter-spacing: -0.015em; line-height: 1.15;
260	  margin-bottom: 56px;
261	}
262	
263	/* ---------- About ---------- */
264	.about__grid { display: grid; grid-template-columns: 1.3fr 1fr; gap: 48px; align-items: start; }
265	.about__text p { margin-bottom: 20px; color: var(--text-dim); font-size: 1.04rem; }
266	.about__text strong { color: var(--text); }
267	.about__text em { color: var(--accent-1); font-style: normal; }
268	
269	.about__cards { display: grid; gap: 18px; }
270	.glass-card {
271	  border: 1px solid var(--border); border-radius: var(--radius);
272	  background: var(--surface); padding: 24px 26px;
273	  transition: transform 0.25s ease, border-color 0.25s ease;
274	}
275	.glass-card:hover { transform: translateY(-4px); border-color: rgba(129, 140, 248, 0.5); }
276	.glass-card__icon { font-size: 1.6rem; margin-bottom: 10px; }
277	.glass-card h3 { font-family: var(--font-display); font-size: 1.05rem; margin-bottom: 6px; }
278	.glass-card p { color: var(--text-dim); font-size: 0.93rem; }
279	
280	/* ---------- Timeline ---------- */
281	.timeline { position: relative; padding-left: 36px; }
282	.timeline::before {
283	  content: ""; position: absolute; left: 8px; top: 6px; bottom: 6px; width: 2px;
284	  background: linear-gradient(180deg, var(--accent-1), var(--accent-2), transparent);
285	  opacity: 0.5;
286	}
287	.timeline__item { position: relative; margin-bottom: 34px; }
288	.timeline__marker {
289	  position: absolute; left: -36px; top: 8px;
290	  width: 18px; height: 18px; border-radius: 50%;
291	  background: var(--bg); border: 3px solid var(--accent-2);
292	}
293	.timeline__item[data-current="true"] .timeline__marker {
294	  border-color: var(--accent-1);
295	  box-shadow: 0 0 0 5px rgba(34, 211, 238, 0.15), 0 0 18px rgba(34, 211, 238, 0.5);
296	}
297	
298	.timeline__card {
299	  border: 1px solid var(--border); border-radius: var(--radius);
300	  background: var(--surface); padding: 28px 30px;
301	  transition: transform 0.25s ease, border-color 0.25s ease, background 0.25s ease;
302	}
303	.timeline__card:hover { transform: translateX(6px); border-color: rgba(34, 211, 238, 0.4); background: var(--surface-strong); }
304	
305	.timeline__head { display: flex; justify-content: space-between; gap: 18px; flex-wrap: wrap; margin-bottom: 14px; }
306	.timeline__head h3 { font-family: var(--font-display); font-size: 1.18rem; line-height: 1.35; }
307	.timeline__sep { color: var(--accent-2); }
308	.timeline__company { color: var(--accent-1); font-weight: 600; font-size: 0.95rem; margin-top: 2px; }
309	.timeline__meta {
310	  display: flex; align-items: center; gap: 10px; flex-wrap: wrap;
311	  color: var(--text-dim); font-size: 0.86rem; font-family: var(--font-mono);
312	}
313	.badge--live {
314	  padding: 3px 12px; border-radius: 999px; font-size: 0.72rem; font-weight: 600;
315	  background: rgba(52, 211, 153, 0.14); color: #34d399; border: 1px solid rgba(52, 211, 153, 0.35);
316	}
317	
318	.timeline__card ul { list-style: none; display: grid; gap: 9px; margin-bottom: 16px; }
319	.timeline__card ul li {
320	  position: relative; padding-left: 22px; color: var(--text-dim); font-size: 0.95rem;
321	}
322	.timeline__card ul li::before {
323	  content: "▸"; position: absolute; left: 0; color: var(--accent-1);
324	}
325	.timeline__card--compact ul { margin-bottom: 0; }
326	
327	.timeline__tags { display: flex; flex-wrap: wrap; gap: 8px; }
328	.timeline__tags span {
329	  font-family: var(--font-mono); font-size: 0.74rem;
330	  padding: 5px 12px; border-radius: 999px;
331	  color: var(--accent-2); background: rgba(129, 140, 248, 0.1);
332	  border: 1px solid rgba(129, 140, 248, 0.25);
333	}
334	
335	/* ---------- Projects ---------- */
336	.projects__grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 22px; }
337	.project {
338	  position: relative;
339	  border: 1px solid var(--border); border-radius: var(--radius);
340	  background: var(--surface); padding: 28px;
341	  display: flex; flex-direction: column;
342	  transition: transform 0.28s ease, border-color 0.28s ease, box-shadow 0.28s ease;
343	}
344	.project:hover {
345	  transform: translateY(-6px);
346	  border-color: rgba(34, 211, 238, 0.45);
347	  box-shadow: 0 18px 50px rgba(0, 0, 0, 0.4);
348	}
349	.project__link-overlay { position: absolute; inset: 0; z-index: 1; border-radius: var(--radius); }
350	.project__top { display: flex; justify-content: space-between; align-items: center; margin-bottom: 16px; }
351	.project__icon { font-size: 1.7rem; }
352	.project__domain {
353	  display: inline-flex; align-items: center; gap: 6px;
354	  font-family: var(--font-mono); font-size: 0.72rem; letter-spacing: 0.08em;
355	  color: var(--accent-1); text-transform: uppercase;
356	}
357	.project h3 { font-family: var(--font-display); font-size: 1.22rem; margin-bottom: 10px; }
358	.project__gh { font-size: 0.72rem; color: var(--accent-1); font-family: var(--font-mono); vertical-align: middle; }
359	.project p { color: var(--text-dim); font-size: 0.93rem; margin-bottom: 16px; }
360	.project__wins { list-style: none; display: grid; gap: 7px; margin-bottom: 18px; }
361	.project__wins li {
362	  position: relative; padding-left: 20px; font-size: 0.87rem; color: var(--text);
363	}
364	.project__wins li::before { content: "✦"; position: absolute; left: 0; color: var(--accent-3); font-size: 0.75rem; top: 2px; }
365	.project__tags { display: flex; flex-wrap: wrap; gap: 7px; margin-top: auto; }
366	.project__tags span {
367	  font-family: var(--font-mono); font-size: 0.72rem;
368	  padding: 4px 11px; border-radius: 999px;
369	  color: var(--text-dim); background: rgba(255, 255, 255, 0.05);
370	  border: 1px solid var(--border);
371	}
372	.project--cta {
373	  align-items: flex-start; justify-content: center; gap: 6px;
374	  background: linear-gradient(145deg, rgba(34, 211, 238, 0.07), rgba(232, 121, 249, 0.06));
375	  border-style: dashed;
376	}
377	
378	/* ---------- Skills ---------- */
379	.skills__grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 22px; }
380	.skill-group {
381	  border: 1px solid var(--border); border-radius: var(--radius);
382	  background: var(--surface); padding: 26px 28px;
383	  transition: border-color 0.25s ease;
384	}
385	.skill-group:hover { border-color: rgba(129, 140, 248, 0.45); }
386	.skill-group h3 {
387	  font-family: var(--font-display); font-size: 1.06rem; margin-bottom: 16px;
388	  display: flex; align-items: center; gap: 10px;
389	}
390	.chips { display: flex; flex-wrap: wrap; gap: 9px; }
391	.chips span {
392	  font-size: 0.83rem; padding: 7px 14px; border-radius: 999px;
393	  color: var(--text-dim); background: rgba(255, 255, 255, 0.045);
394	  border: 1px solid var(--border);
395	  transition: all 0.2s ease; cursor: default;
396	}
397	.chips span:hover {
398	  color: var(--text); border-color: var(--accent-1);
399	  background: rgba(34, 211, 238, 0.08); transform: translateY(-2px);
400	}
401	
402	/* ---------- Credentials ---------- */
403	.cred__grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 22px; }
404	.cred__col {
405	  border: 1px solid var(--border); border-radius: var(--radius);
406	  background: var(--surface); padding: 28px;
407	}
408	.cred__heading { font-family: var(--font-display); font-size: 1.1rem; margin-bottom: 18px; }
409	.cred__list { list-style: none; display: grid; gap: 12px; }
410	.cred__list li {
411	  position: relative; padding-left: 20px; color: var(--text-dim); font-size: 0.92rem;
412	}
413	.cred__list li::before { content: "◆"; position: absolute; left: 0; top: 3px; color: var(--accent-2); font-size: 0.6rem; }
414	.cred__list strong { color: var(--text); }
415	.cred__list--edu li { display: grid; gap: 2px; }
416	.cred__list--edu span { font-size: 0.85rem; }
417	
418	/* ---------- Contact ---------- */
419	.section--contact {
420	  background:
421	    radial-gradient(800px 400px at 50% 100%, rgba(129, 140, 248, 0.12), transparent 65%),
422	    var(--bg-alt);
423	  text-align: center;
424	}
425	.contact__inner { max-width: 760px; }
426	.contact__blurb { color: var(--text-dim); font-size: 1.08rem; max-width: 560px; margin: 0 auto 36px; }
427	.contact__actions { margin-bottom: 34px; }
428	.contact__links {
429	  display: flex; justify-content: center; gap: 26px; flex-wrap: wrap;
430	  color: var(--text-dim); font-size: 0.95rem;
431	}
432	.contact__links a { color: var(--text-dim); text-decoration: none; transition: color 0.2s ease; }
433	.contact__links a:hover { color: var(--accent-1); }
434	
435	/* ---------- Footer ---------- */
436	.footer { border-top: 1px solid var(--border); padding: 28px 0; }
437	.footer__inner { display: flex; justify-content: space-between; align-items: center; gap: 16px; flex-wrap: wrap; }
438	.footer p { color: var(--text-dim); font-size: 0.88rem; }
439	.footer__top {
