  1	/* ============================================================
  2	   Nikhil Komakula — Portfolio interactions
  3	   ============================================================ */
  4	(() => {
  5	  "use strict";
  6	
  7	  const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
  8	
  9	  /* ---------- Footer year ---------- */
 10	  const yearEl = document.getElementById("year");
 11	  if (yearEl) yearEl.textContent = new Date().getFullYear();
 12	
 13	  /* ---------- Nav: scrolled state + mobile menu ---------- */
 14	  const nav = document.getElementById("nav");
 15	  const burger = document.getElementById("navBurger");
 16	  const navLinks = document.getElementById("navLinks");
 17	
 18	  const onScrollNav = () => {
 19	    nav.classList.toggle("nav--scrolled", window.scrollY > 20);
 20	  };
 21	  window.addEventListener("scroll", onScrollNav, { passive: true });
 22	  onScrollNav();
 23	
 24	  if (burger && navLinks) {
 25	    burger.addEventListener("click", () => {
 26	      const open = navLinks.classList.toggle("is-open");
 27	      burger.classList.toggle("is-open", open);
 28	      burger.setAttribute("aria-expanded", String(open));
 29	    });
 30	    navLinks.querySelectorAll("a").forEach((a) =>
 31	      a.addEventListener("click", () => {
 32	        navLinks.classList.remove("is-open");
 33	        burger.classList.remove("is-open");
 34	        burger.setAttribute("aria-expanded", "false");
 35	      })
 36	    );
 37	  }
 38	
 39	  /* ---------- Scroll progress bar ---------- */
 40	  const scrollBar = document.getElementById("scrollBar");
 41	  const onScrollBar = () => {
 42	    const max = document.documentElement.scrollHeight - window.innerHeight;
 43	    scrollBar.style.width = `${max > 0 ? (window.scrollY / max) * 100 : 0}%`;
 44	  };
 45	  window.addEventListener("scroll", onScrollBar, { passive: true });
 46	  onScrollBar();
 47	
 48	  /* ---------- Reveal on scroll ---------- */
 49	  const revealEls = document.querySelectorAll(".reveal");
 50	  if ("IntersectionObserver" in window && !prefersReducedMotion) {
 51	    const io = new IntersectionObserver(
 52	      (entries) => {
 53	        entries.forEach((entry) => {
 54	          if (entry.isIntersecting) {
 55	            entry.target.classList.add("is-visible");
 56	            io.unobserve(entry.target);
 57	          }
 58	        });
 59	      },
 60	      { threshold: 0.12, rootMargin: "0px 0px -40px 0px" }
 61	    );
 62	    revealEls.forEach((el, i) => {
 63	      el.style.transitionDelay = `${Math.min((i % 6) * 60, 300)}ms`;
 64	      io.observe(el);
 65	    });
 66	  } else {
 67	    revealEls.forEach((el) => el.classList.add("is-visible"));
 68	  }
 69	
 70	  /* ---------- Typing effect ---------- */
 71	  const typedEl = document.getElementById("typed");
 72	  const phrases = [
 73	    "Generative AI Solutions",
 74	    "Agentic AI Systems",
 75	    "RAG Pipelines",
 76	    "MLOps & LLMOps Platforms",
 77	    "AI Governance Frameworks",
 78	    "Production-Ready ML",
 79	  ];
 80	  if (typedEl) {
 81	    if (prefersReducedMotion) {
 82	      typedEl.textContent = phrases[0];
 83	    } else {
 84	      let pi = 0, ci = 0, deleting = false;
 85	      const tick = () => {
 86	        const phrase = phrases[pi];
 87	        ci += deleting ? -1 : 1;
 88	        typedEl.textContent = phrase.slice(0, ci);
 89	
 90	        let delay = deleting ? 34 : 68;
 91	        if (!deleting && ci === phrase.length) {
 92	          delay = 1800;
 93	          deleting = true;
 94	        } else if (deleting && ci === 0) {
 95	          deleting = false;
 96	          pi = (pi + 1) % phrases.length;
 97	          delay = 380;
 98	        }
 99	        setTimeout(tick, delay);
100	      };
101	      tick();
102	    }
103	  }
104	
105	  /* ---------- Animated counters ---------- */
106	  const counters = document.querySelectorAll(".stat__num");
107	  const animateCounter = (el) => {
108	    const target = parseInt(el.dataset.count, 10);
109	    const suffix = el.dataset.suffix || "";
110	    if (prefersReducedMotion) {
111	      el.textContent = target + suffix;
112	      return;
113	    }
114	    const duration = 1400;
115	    const start = performance.now();
116	    const step = (now) => {
117	      const p = Math.min((now - start) / duration, 1);
118	      const eased = 1 - Math.pow(1 - p, 3);
119	      el.textContent = Math.round(eased * target) + suffix;
120	      if (p < 1) requestAnimationFrame(step);
121	    };
122	    requestAnimationFrame(step);
123	  };
124	  if ("IntersectionObserver" in window) {
125	    const cio = new IntersectionObserver(
126	      (entries) => {
127	        entries.forEach((entry) => {
128	          if (entry.isIntersecting) {
129	            animateCounter(entry.target);
130	            cio.unobserve(entry.target);
131	          }
132	        });
133	      },
134	      { threshold: 0.6 }
135	    );
136	    counters.forEach((c) => cio.observe(c));
137	  } else {
138	    counters.forEach(animateCounter);
139	  }
140	
141	  /* ---------- Neural network canvas (hero) ---------- */
142	  const canvas = document.getElementById("neuralCanvas");
143	  if (canvas && !prefersReducedMotion) {
144	    const ctx = canvas.getContext("2d");
145	    let width, height, nodes, raf;
146	    const DPR = Math.min(window.devicePixelRatio || 1, 2);
147	    const mouse = { x: null, y: null };
148	
149	    const NODE_COLOR = "rgba(148, 163, 197, 0.9)";
150	    const LINK_DIST = 150;
151	
152	    function resize() {
153	      const rect = canvas.getBoundingClientRect();
154	      width = rect.width;
155	      height = rect.height;
156	      canvas.width = width * DPR;
157	      canvas.height = height * DPR;
158	      ctx.setTransform(DPR, 0, 0, DPR, 0, 0);
159	      initNodes();
160	    }
161	
162	    function initNodes() {
163	      const count = Math.min(Math.floor((width * height) / 16000), 90);
164	      nodes = Array.from({ length: count }, () => ({
165	        x: Math.random() * width,
166	        y: Math.random() * height,
167	        vx: (Math.random() - 0.5) * 0.35,
168	        vy: (Math.random() - 0.5) * 0.35,
169	        r: Math.random() * 1.6 + 0.8,
170	      }));
171	    }
172	
173	    function draw() {
174	      ctx.clearRect(0, 0, width, height);
175	
176	      for (const n of nodes) {
177	        n.x += n.vx;
178	        n.y += n.vy;
179	        if (n.x < 0 || n.x > width) n.vx *= -1;
180	        if (n.y < 0 || n.y > height) n.vy *= -1;
181	      }
182	
183	      // Links
184	      for (let i = 0; i < nodes.length; i++) {
185	        for (let j = i + 1; j < nodes.length; j++) {
186	          const dx = nodes[i].x - nodes[j].x;
187	          const dy = nodes[i].y - nodes[j].y;
188	          const dist = Math.hypot(dx, dy);
189	          if (dist < LINK_DIST) {
190	            const alpha = (1 - dist / LINK_DIST) * 0.35;
191	            ctx.strokeStyle = `rgba(129, 140, 248, ${alpha})`;
192	            ctx.lineWidth = 1;
193	            ctx.beginPath();
194	            ctx.moveTo(nodes[i].x, nodes[i].y);
195	            ctx.lineTo(nodes[j].x, nodes[j].y);
196	            ctx.stroke();
197	          }
198	        }
199	        // Mouse links
200	        if (mouse.x !== null) {
201	          const dx = nodes[i].x - mouse.x;
202	          const dy = nodes[i].y - mouse.y;
203	          const dist = Math.hypot(dx, dy);
204	          if (dist < LINK_DIST * 1.2) {
205	            const alpha = (1 - dist / (LINK_DIST * 1.2)) * 0.5;
206	            ctx.strokeStyle = `rgba(34, 211, 238, ${alpha})`;
207	            ctx.lineWidth = 1;
208	            ctx.beginPath();
209	            ctx.moveTo(nodes[i].x, nodes[i].y);
210	            ctx.lineTo(mouse.x, mouse.y);
211	            ctx.stroke();
212	          }
213	        }
214	      }
215	
216	      // Nodes
217	      ctx.fillStyle = NODE_COLOR;
218	      for (const n of nodes) {
219	        ctx.beginPath();
220	        ctx.arc(n.x, n.y, n.r, 0, Math.PI * 2);
221	        ctx.fill();
222	      }
223	
224	      raf = requestAnimationFrame(draw);
225	    }
226	
227	    const hero = document.getElementById("hero");
228	    hero.addEventListener("mousemove", (e) => {
229	      const rect = canvas.getBoundingClientRect();
230	      mouse.x = e.clientX - rect.left;
231	      mouse.y = e.clientY - rect.top;
232	    });
233	    hero.addEventListener("mouseleave", () => {
234	      mouse.x = null;
235	      mouse.y = null;
236	    });
237	
238	    // Pause when hero is off-screen
239	    if ("IntersectionObserver" in window) {
240	      new IntersectionObserver(
241	        (entries) => {
242	          entries.forEach((entry) => {
243	            if (entry.isIntersecting) {
244	              if (!raf) raf = requestAnimationFrame(draw);
245	            } else {
246	              cancelAnimationFrame(raf);
247	              raf = null;
248	            }
249	          });
250	        },
251	        { threshold: 0 }
252	      ).observe(canvas);
253	    }
254	
255	    window.addEventListener("resize", resize, { passive: true });
256	    resize();
257	    raf = requestAnimationFrame(draw);
258	  }
259	})();

