python3 - <<'PY'
from html.parser import HTMLParser
from pathlib import Path
class P(HTMLParser):
    def __init__(self):
        super().__init__(); self.ids=set(); self.hrefs=[]
    def handle_starttag(self, tag, attrs):
        d=dict(attrs)
        if 'id' in d: self.ids.add(d['id'])
        if tag=='a' and d.get('href','').startswith('#'): self.hrefs.append(d['href'][1:])
p=P(); p.feed(Path('index.html').read_text())
missing=[h for h in p.hrefs if h and h not in p.ids]
print('ids',len(p.ids),'fragment-links',len(p.hrefs),'missing-fragments',missing)
